import{_ as t,o as a,c as o,ai as n}from"./chunks/framework.CsYGeNYI.js";const g=JSON.parse('{"title":"Agent Bootstrapping","description":"","frontmatter":{"summary":"Agent bootstrapping ritual that seeds the workspace and identity files","read_when":["Understanding what happens on the first agent run","Explaining where bootstrapping files live","Debugging onboarding identity setup"],"title":"Agent Bootstrapping","sidebarTitle":"Bootstrapping"},"headers":[],"relativePath":"start/bootstrapping.md","filePath":"start/bootstrapping.md","lastUpdated":1771906665000}'),s={name:"start/bootstrapping.md"};function r(i,e,d,p,c,h){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="agent-bootstrapping" tabindex="-1"><a class="header-anchor" href="#agent-bootstrapping">#</a> Agent Bootstrapping</h1><p>Bootstrapping is the <strong>first‑run</strong> ritual that prepares an agent workspace and collects identity details. It happens after onboarding, when the agent starts for the first time.</p><h2 id="what-bootstrapping-does" tabindex="-1"><a class="header-anchor" href="#what-bootstrapping-does">#</a> What bootstrapping does</h2><p>On the first agent run, OpenSoul bootstraps the workspace (default <code>~/.opensoul/workspace</code>):</p><ul><li>Seeds <code>AGENTS.md</code>, <code>BOOTSTRAP.md</code>, <code>IDENTITY.md</code>, <code>USER.md</code>.</li><li>Runs a short Q&amp;A ritual (one question at a time).</li><li>Writes identity + preferences to <code>IDENTITY.md</code>, <code>USER.md</code>, <code>SOUL.md</code>.</li><li>Removes <code>BOOTSTRAP.md</code> when finished so it only runs once.</li></ul><h2 id="where-it-runs" tabindex="-1"><a class="header-anchor" href="#where-it-runs">#</a> Where it runs</h2><p>Bootstrapping always runs on the <strong>gateway host</strong>. If the macOS app connects to a remote Gateway, the workspace and bootstrapping files live on that remote machine.</p><blockquote><p><strong>Note:</strong> When the Gateway runs on another machine, edit workspace files on the gateway host (for example, <code>user@gateway-host:~/.opensoul/workspace</code>).</p></blockquote><h2 id="related-docs" tabindex="-1"><a class="header-anchor" href="#related-docs">#</a> Related docs</h2><ul><li>macOS app onboarding: <a href="/docs/start/onboarding">Onboarding</a></li><li>Workspace layout: <a href="/docs/concepts/agent-workspace">Agent workspace</a></li></ul>',10)])])}const u=t(s,[["render",r]]);export{g as __pageData,u as default};
